window.onerror = function(msg, src, line, col, err) {
  document.body.style.background = '#0a0809';
  document.body.style.color = '#e8ddd0';
  document.body.style.fontFamily = 'Georgia, serif';
  document.body.style.padding = '2rem';
  document.body.style.display = 'flex';
  document.body.style.flexDirection = 'column';
  document.body.style.alignItems = 'center';
  document.body.style.justifyContent = 'center';
  document.body.style.height = '100vh';
  document.body.innerHTML = '<h1 style="color:#c9a84c;font-size:1.5rem;margin-bottom:1rem">CASTLE RUN</h1><p style="color:#a89880;font-size:0.9rem;text-align:center">Failed to load: ' + msg + '<br><br>Try opening in Chrome on a PC,<br>or use the Claude app version.</p>';
  return true;
};

