// Register upgraded cards into CARDS with a '+' suffix key
Object.entries(CARD_UPGRADES).forEach(([key, card]) => {
  CARDS[key + '+'] = card;
});

// Upgrade a card in the deck — replaces first instance with upgraded version
function upgradeCard(cardKey) {
  const upgradeKey = cardKey + '+';
  if (!CARD_UPGRADES[cardKey]) {
    showMsg('This card cannot be upgraded.');
    return false;
  }
  const idx = G.deck.indexOf(cardKey);
  if (idx >= 0) {
    G.deck[idx] = upgradeKey;
    // Also replace in draw pile and hand if present
    const drawIdx = G.drawPile.indexOf(cardKey);
    if (drawIdx >= 0) G.drawPile[drawIdx] = upgradeKey;
    const handIdx = G.hand.indexOf(cardKey);
    if (handIdx >= 0) G.hand[handIdx] = upgradeKey;
    return true;
  }
  return false;
}

